const data = $input.first().json;
const shortages = data.shortageDetails || [];
const restaurant = data.restaurant;
const week = data.shiftPlan.weekStartDate;

const rows = shortages.map(s => 
  `<tr><td style="padding:8px 12px;border-bottom:1px solid #fecaca;">${s.day}</td><td style="padding:8px 12px;border-bottom:1px solid #fecaca;">${s.shift}</td><td style="padding:8px 12px;border-bottom:1px solid #fecaca;">${s.role}</td><td style="padding:8px 12px;border-bottom:1px solid #fecaca;font-weight:600;color:#dc2626;">${s.assigned}/${s.needed} (${s.gap} missing)</td></tr>`
).join('');

const totalGap = shortages.reduce((sum, s) => sum + (s.gap || 0), 0);

const html = `<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:600px;margin:0 auto;padding:30px 20px;">
  <h2 style="color:#dc2626;">⚠️ Staff Shortage Alert</h2>
  <p>The shift plan for <strong>week of ${week}</strong> has <strong>${totalGap} unfilled positions</strong>:</p>
  <table style="width:100%;border-collapse:collapse;margin:20px 0;background:#FEF2F2;border:1px solid #FECACA;border-radius:8px;">
    <tr style="background:#FEE2E2;"><th style="padding:10px 12px;text-align:left;">Day</th><th style="padding:10px 12px;text-align:left;">Shift</th><th style="padding:10px 12px;text-align:left;">Role</th><th style="padding:10px 12px;text-align:left;">Status</th></tr>
    ${rows}
  </table>
  <p>Please find additional staff or adjust the schedule.</p>
  <p><a href="https://yourdomain.com/dashboard/shifts" style="display:inline-block;background:#dc2626;color:white;padding:12px 24px;border-radius:8px;text-decoration:none;font-weight:600;">Open Shift Planner</a></p>
</div>`;

const plainText = shortages.map(s => `⚠️ ${s.day} ${s.shift}: Need ${s.needed} ${s.role}, only ${s.assigned} assigned (${s.gap} missing)`).join('\n');

return [{ json: { html, plainText, totalGap, restaurant, week } }];
